// Data layer for the model-centric views (homepage models section,
// /models/[slug], per-bench model lists). Types, constants, and pure
// transforms over public/data/models.json (regenerated by
// scripts/build_model_index.py on every publish). This module is
// client-component-safe: the fs reader lives in ./models.server.

export type Bench = "hard" | "mega" | "cuda"

export interface ModelCell {
  run_id: string | null
  correct: boolean
  score: number | null
  verdict: string
  valid: boolean
  elapsed_seconds?: number | null
  tok_s?: number | null
  ctx?: Record<string, number>
  framework?: string | null
  solution_url: string | null
  trace_url: string | null
}

export interface FlagEntry {
  run_id: string
  verdict: string
  summary: string
}

export interface GpuBlock {
  label: string | null
  harness: string | null
  effort: string | null
  passed: number
  total_problems: number
  perf: number | null
  cells: Record<string, ModelCell>
}

export interface BenchBlock extends GpuBlock {
  audited: number
  flagged: number
  flags: FlagEntry[]
  gpus: Record<string, GpuBlock>
}

export interface LegacyBlock {
  best_pass_count: number
  total_problems: number
  labels: string[]
}

export interface ModelEntry {
  slug: string
  name: string
  lab: string
  benches: Partial<Record<Bench, BenchBlock>>
  legacy: Record<string, LegacyBlock>
  totals: { audited: number; flagged: number }
}

export interface ModelIndex {
  generated: string
  benches: Record<
    string,
    {
      problems: string[]
      gpu: string
      gpus?: string[]
      gpu_labels?: Record<string, string>
    }
  >
  methodology: string
  models: ModelEntry[]
}

